// Niches × towns to scan. Edit freely — each line = one Places search.
const queries = [
  'car detailing in West Chester PA',
  'landscaping company in Downingtown PA',
  'hair salon in Coatesville PA',
  'cleaning service in Exton PA',
  'auto repair shop in Phoenixville PA',
  'contractor in Kennett Square PA',
  'barbershop in West Chester PA',
  'restaurant in Coatesville PA'
];
return queries.map(q => ({ json: { query: q } }));

// Keep businesses with NO real website (none, or social-media-only)
const socialOnly = /facebook\.com|instagram\.com|linktr\.ee|yelp\.com|google\.com/i;
const found = [];
const seen = new Set();
for (const item of $input.all()) {
  const places = item.json.places || [];
  for (const p of places) {
    const name = p.displayName && p.displayName.text ? p.displayName.text : null;
    if (!name) continue;
    const site = p.websiteUri || '';
    const noSite = !site || socialOnly.test(site);
    if (!noSite) continue;
    const key = name.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    found.push({
      business: name,
      phone: p.nationalPhoneNumber || '',
      address: p.formattedAddress || '',
      rating: p.rating || null,
      reviews: p.userRatingCount || 0,
      site_status: site ? 'social only: ' + site : 'no website'
    });
  }
}
return [{ json: { found } }];

const found = $('Filter No-Website').first().json.found || [];
const existing = new Set();
for (const item of $input.all()) {
  const l = item.json || {};
  if (l.business) existing.add(String(l.business).toLowerCase());
  if (l.name) existing.add(String(l.name).toLowerCase());
}
const fresh = found.filter(f => !existing.has(f.business.toLowerCase()));
// cap so a first run doesn't dump 100 leads at once
return fresh.slice(0, 25).map(f => ({ json: f }));

const rows = $('Dedupe vs CRM').all();
if (!rows.length) return [];
const lines = rows.map(r => {
  const f = r.json;
  return `• ${f.business} — ${f.phone || 'no phone listed'}\n  ${f.site_status} · ${f.address}${f.rating ? ' · ' + f.rating + '★ (' + f.reviews + ')' : ''}`;
});
return [{ json: { count: rows.length, list: lines.join('\n\n') } }];

